'use client';

import React from 'react';
import styled from 'styled-components';

const Loader = () => {
  return (
    <StyledWrapper>
      <svg id="svg-global" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 94 136" height={136} width={94}>
        {/* (SVG content ตามที่คุณมี) */}
        <g id="particles">
          <circle className="particle p1" cx="40" cy="80" r="4" fill="#6c63ff" />
          <circle className="particle p2" cx="60" cy="90" r="3" fill="#6c63ff" />
          <circle className="particle p3" cx="50" cy="70" r="5" fill="#6c63ff" />
        </g>
      </svg>
    </StyledWrapper>
  );
};

const StyledWrapper = styled.div`
  #svg-global {
    zoom: 1.2;
    overflow: visible;
  }

  @keyframes fade-particles {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.5; }
  }

  @keyframes floatUp {
    0% { transform: translateY(0); opacity: 0; }
    10% { opacity: 1; }
    100% { transform: translateY(-40px); opacity: 0; }
  }

  #particles { animation: fade-particles 5s infinite alternate; }
  .particle { animation: floatUp linear infinite; }

  .p1 { animation-duration: 2.2s; animation-delay: 0s; }
  .p2 { animation-duration: 2.5s; animation-delay: 0.3s; }
  .p3 { animation-duration: 2s; animation-delay: 0.6s; }
`;

export default Loader;
